export default async function handler(req, res) {
  if (req.method !== 'POST') return res.status(405).end();

  // 使用最小测试图片（1x1像素白色JPEG）
  const testImage = 'data:image/jpeg;base64,';
  
  try {
    const response = await fetch('https://api.deepseek.com/v1/ocr', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${process.env.DEEPSEEK_API_KEY}`,
      },
      body: JSON.stringify({
        image: testImage,
        language: 'zh'
      }),
    });

    const result = {
      status: response.status,
      endpoint: 'https://api.deepseek.com/v1/ocr',
      response: await response.json().catch(() => 'Failed to parse response')
    };
    
    res.status(200).json(result);
  } catch (error) {
    res.status(500).json({
      error: error.message,
      endpoint: 'https://api.deepseek.com/v1/ocr'
    });
  }
}